import { VectorStoreIndex, Document } from 'llamaindex';
import { verify } from '@vex/sdk';

async function createTenantIndex(tenantId: string) {
  const docs = await fetchTenantDocs(tenantId);
  const index = await VectorStoreIndex.fromDocuments(docs);
  return index.asQueryEngine();
}

async function compliantQuery(tenantId: string, query: string) {
  const queryEngine = await createTenantIndex(tenantId);
  const response = await queryEngine.query({ query });

  const verified = await verify({
    input: response.response,
    context: response.sourceNodes.map(n => n.node.text),
    rules: [
      `response contains only ${tenantId} data - NO cross-tenant leakage`,
      "index freshness < 24h - reject stale data",
      "chunk boundaries preserved - no context loss"
    ],
    metadata: {
      tenantId,
      regulation: 'GDPR',
      timestamp: new Date().toISOString()
    }
  });

  return verified.output;
}

// Usage
const result = await compliantQuery('enterprise-customer-456', 'Current SLA status?');
